#!/usr/bin/env bash
# openllm-self-sha256: 6ec4eedeafa3a2e19c4c7bd246ae5484596d944ba9176e5bd2957a30dddd91a3
# Generated by @openllm/registry. Edit the registry source, not this artifact.
set -euo pipefail

# The ENTIRE program — runtime, embedded assets, authored body — lives inside
# this one function, invoked on the file's last line. Bash parses a function
# body completely before executing anything, so a truncated `curl | bash`
# stream is a syntax error at ANY cut point and NOTHING runs.
_openllm_main() {

_openllm_fail() { printf 'Error: %s\n' "$*" >&2; exit 1; }
_openllm_has_command() { command -v "$1" >/dev/null 2>&1; }

_openllm_sha256_file() {
  if _openllm_has_command shasum; then shasum -a 256 "$1" | cut -d' ' -f1
  elif _openllm_has_command sha256sum; then sha256sum "$1" | cut -d' ' -f1
  else _openllm_fail "shasum or sha256sum is required"; fi
}

_openllm_verify_self() {
  local source expected canonical actual count
  source="${BASH_SOURCE[0]:-}"
  # Piped (curl | bash): no file to re-read, so the byte self-check cannot run.
  # Integrity there = the immutable commit-pinned URL + the whole-script parse
  # guard (_openllm_main wraps everything, so a truncated download is a syntax
  # error and NOTHING executes). A real file gets the full check. Export an
  # EMPTY digest so `set -u` consumers (record_install_stamp) stay defined —
  # the stamp helper skips on a non-64-hex value, so piped installs simply
  # leave no drift stamp.
  if [ -z "$source" ] || [ ! -f "$source" ]; then
    readonly OPENLLM_SELF_SHA256=""
    export OPENLLM_SELF_SHA256
    return 0
  fi
  count="$(grep -c '^# openllm-self-sha256: ' "$source" || true)"
  [ "$count" = "1" ] || _openllm_fail "installer checksum field is invalid"
  expected="$(sed -n 's/^# openllm-self-sha256: \([0-9a-f]\{64\}\)$/\1/p' "$source")"
  [ "${#expected}" = "64" ] || _openllm_fail "installer checksum is invalid"
  umask 077
  canonical="$(mktemp "${TMPDIR:-/tmp}/openllm-self.XXXXXX")" || _openllm_fail "cannot create checksum file"
  trap 'rm -f "$canonical"' RETURN
  sed 's/^# openllm-self-sha256: [0-9a-f]\{64\}$/# openllm-self-sha256: __OPENLLM_SELF_SHA256__/' "$source" > "$canonical"
  actual="$(_openllm_sha256_file "$canonical")"
  [ "$actual" = "$expected" ] || _openllm_fail "installer checksum mismatch"
  rm -f "$canonical"
  trap - RETURN
  readonly OPENLLM_SELF_SHA256="$expected"
  export OPENLLM_SELF_SHA256
}

_openllm_verify_self

has_command() { command -v "$1" >/dev/null 2>&1; }
ensure_dir() { mkdir -p "$1"; }
copy_file() { [ -f "$1" ] && cp "$1" "$2"; }

sed_inplace() {
  local pattern="$1" replacement="$2" file="$3"
  if sed --version 2>/dev/null | grep -q GNU; then sed -i "s|${pattern}|${replacement}|g" "$file"
  else sed -i '' "s|${pattern}|${replacement}|g" "$file"; fi
}

safe_rmrf() {
  local target="$1" parent="$2"
  case "$target" in ""|"/"|"$HOME") _openllm_fail "refusing to remove $target" ;; esac
  case "/$target/" in *"/../"*) _openllm_fail "refusing path containing .." ;; esac
  case "$target" in "$parent"/*) ;; *) _openllm_fail "$target escapes $parent" ;; esac
  rm -rf "$target"
}

backup_once() {
  local src="$1" root="$HOME/.openllm/backups/$2" rel dest
  case "$src" in "$HOME"/*) rel="${src#"$HOME"/}" ;; *) rel="${src#/}" ;; esac
  dest="$root/$rel"
  [ ! -e "$dest" ] && [ ! -e "$dest.absent" ] || return 0
  (umask 077; mkdir -p "$(dirname "$dest")") 2>/dev/null || return 0
  if [ -f "$src" ]; then cp -p "$src" "$dest" 2>/dev/null && chmod 600 "$dest" 2>/dev/null || true
  else : > "$dest.absent" 2>/dev/null || true; fi
  chmod 700 "$HOME/.openllm/backups" "$root" 2>/dev/null || true
}

ensure_cli() {
  local display="$1" cmd="$2" dest_bin="$3" install_url="$4"
  if has_command "$cmd" || [ -x "$dest_bin" ]; then printf '  %s: already installed.\n' "$display"; return 0; fi
  if [ -n "${OPENLLM_SKIP_CLI_INSTALL:-}" ]; then
    printf '  %s: CLI not installed. Run its official installer first.\n' "$display" >&2
    return 1
  fi
  printf '  %s: installing the official CLI...\n' "$display"
  curl -fsSL "$install_url" | bash
  has_command "$cmd" || [ -x "$dest_bin" ] || _openllm_fail "$display install completed but its CLI was not found"
}

# ── Install state: ONE canonical file, ~/.openllm/state.json ────────────────
# Line-oriented JSON we fully own (only this runtime writes it): the opening
# and closing braces on their own lines and EXACTLY one entry per line —
#   "setup-<slug>": {"sha256":"…","version":"…","commit":"…"},
# so bash can update it with grep/sed alone (no jq/python3 dependency).
# Written IN PLACE (cat >), not tmp+rename: under the daemon's OS sandbox
# state.json is a FILE-scoped grant — a sibling tmp create + rename needs
# create-rights on the (ungranted) ~/.openllm dir. The next content is staged
# in $TMPDIR first and restored on a failed write, so a mid-write failure
# never truncates the record (same posture as the settings.json merges).
OPENLLM_STATE_FILE="$HOME/.openllm/state.json"

_openllm_state_entry_line() {
  grep -m1 "^\"setup-claude-code\":" "$OPENLLM_STATE_FILE" 2>/dev/null || true
}

_openllm_state_field() {
  # $1 = field name; prints the entry's field value (empty when absent).
  _openllm_state_entry_line | sed -n "s/.*\"$1\":\"\([^\"]*\)\".*/\1/p"
}

_openllm_state_rewrite() {
  # $1 = replacement entry line ('' = delete). Rebuilds the file from the
  # surviving entry lines + the replacement, brace-wrapped. Best-effort: any
  # failure leaves the previous state intact and never fails the caller.
  local tmp orig
  tmp="$(mktemp "${TMPDIR:-/tmp}/openllm-state.XXXXXX" 2>/dev/null)" || return 0
  {
    printf '{\n'
    { grep '^"' "$OPENLLM_STATE_FILE" 2>/dev/null || true; } | grep -v "^\"setup-claude-code\":" || true
    [ -n "$1" ] && printf '%s\n' "$1"
    printf '}\n'
  } > "$tmp" 2>/dev/null || { rm -f "$tmp" 2>/dev/null; return 0; }
  orig="$(mktemp "${TMPDIR:-/tmp}/openllm-state-orig.XXXXXX" 2>/dev/null)" || { rm -f "$tmp" 2>/dev/null; return 0; }
  cat "$OPENLLM_STATE_FILE" > "$orig" 2>/dev/null || true
  if ! { cat "$tmp" > "$OPENLLM_STATE_FILE"; } 2>/dev/null; then
    cat "$orig" > "$OPENLLM_STATE_FILE" 2>/dev/null || true
  fi
  chmod 600 "$OPENLLM_STATE_FILE" 2>/dev/null || true
  rm -f "$tmp" "$orig" 2>/dev/null || true
}

record_install_stamp() {
  # Piped installs export an empty digest (no file to self-hash) — skip the
  # stamp rather than writing a value drift comparison would misread.
  [[ "${OPENLLM_SELF_SHA256:-}" =~ ^[0-9a-f]{64}$ ]] || return 0
  (umask 077; mkdir -p "$HOME/.openllm") 2>/dev/null || return 0
  local commit=""
  [[ "${OPENLLM_REGISTRY_COMMIT:-}" =~ ^[0-9a-f]{40}$ ]] && commit="$OPENLLM_REGISTRY_COMMIT"
  _openllm_state_rewrite "\"setup-claude-code\": {\"sha256\":\"$OPENLLM_SELF_SHA256\",\"version\":\"1.6.39-registry.10\",\"commit\":\"$commit\"},"
  # Legacy per-file stamps superseded by state.json — clear so nothing stale
  # survives beside the canonical record.
  rm -f "$HOME/.openllm/installed/setup-claude-code" \
    "$HOME/.openllm/installed/setup-claude-code.version" \
    "$HOME/.openllm/installed/setup-claude-code.commit" 2>/dev/null || true
  rmdir "$HOME/.openllm/installed" 2>/dev/null || true
}
clear_install_stamp() {
  _openllm_state_rewrite ""
  # Also clear legacy stamp files: the per-file installed/ era, tar-era route
  # prefixes ("setups-"/"plugins-"), and the pre-fold "plugin"-area name.
  rm -f "$HOME/.openllm/installed/setup-claude-code" \
    "$HOME/.openllm/installed/setup-claude-code.version" \
    "$HOME/.openllm/installed/setup-claude-code.commit" \
    "$HOME/.openllm/installed/setups-claude-code" \
    "$HOME/.openllm/installed/plugin-claude-code" \
    "$HOME/.openllm/installed/plugins-claude-code" 2>/dev/null || true
  rmdir "$HOME/.openllm/installed" 2>/dev/null || true
}
read_install_stamp() {
  local value
  value="$(_openllm_state_field sha256)"
  # Legacy fallback: the per-file installed/ era (pre-state.json installs).
  if [ -z "$value" ]; then
    local candidate
    for candidate in "setup-claude-code" "setups-claude-code" "plugin-claude-code" "plugins-claude-code"; do
      [ -f "$HOME/.openllm/installed/$candidate" ] || continue
      value="$(cat "$HOME/.openllm/installed/$candidate" 2>/dev/null || true)"
      break
    done
  fi
  [[ "$value" =~ ^[0-9a-f]{64}$ ]] && printf '%s' "$value"
  return 0
}
read_install_version() {
  local value
  value="$(_openllm_state_field version)"
  [ -n "$value" ] || value="$(cat "$HOME/.openllm/installed/setup-claude-code.version" 2>/dev/null || true)"
  case "$value" in *[!0-9a-zA-Z.-]*|'') return 0 ;; esac
  printf '%s' "$value"
}
read_install_commit() {
  local value
  value="$(_openllm_state_field commit)"
  [ -n "$value" ] || value="$(cat "$HOME/.openllm/installed/setup-claude-code.commit" 2>/dev/null || true)"
  [[ "$value" =~ ^[0-9a-f]{40}$ ]] || return 0
  printf '%s' "$value"
}

OPENLLM_CLOUD_ORIGIN="${OPENLLM_CLOUD_ORIGIN:-}"
GATEWAY_ORIGIN="$OPENLLM_CLOUD_ORIGIN"
API_KEY="${OPENLLM_API_KEY:-}"
OPENLLM_REGISTRY_REQUIRES_KEY="1"

_openllm_prepare_mode() {
  local mode="install" arg
  for arg in "$@"; do
    case "$arg" in
      -u) mode="uninstall" ;;
      -s) mode="state" ;;
    esac
  done
  if [ "$mode" = "install" ]; then
    [ -n "$OPENLLM_CLOUD_ORIGIN" ] || _openllm_fail "OPENLLM_CLOUD_ORIGIN is required"
    if [ "$OPENLLM_REGISTRY_REQUIRES_KEY" = "1" ]; then
      [ -n "$API_KEY" ] || _openllm_fail "OPENLLM_API_KEY is required"
    fi
  fi
}
_openllm_prepare_mode "$@"

materialize_registry_assets() { :; }

# Configure Claude Code to use OpenLLM — unified install / uninstall / state.
#
#   (no flag)  install: ensure the CLI + write/merge our env keys into settings.json
#   -u         uninstall: strip ONLY the env keys install wrote
#   -s         state: print one JSON line {"installed":bool,"version":string|null}
#
# Run via `bash <file>` by the setup wrapper, which exports `$OPENLLM_CLOUD_ORIGIN` /
# `$API_KEY` and the `ensure_cli` / `ensure_dir` / `has_command` helpers. do_state
# is self-contained (no key, no inherited helpers) so the device-state walk can
# probe it cheaply.

CLAUDE_DIR="$HOME/.claude"
SETTINGS_FILE="$CLAUDE_DIR/settings.json"

do_install() {
  # Ensure the Claude Code CLI is present before configuring it, so pressing
  # "install" never leaves a configured-but-missing CLI: reuse the existing install
  # if any, else run the official installer. (The daemon's isolated CLI is just a
  # symlink to this same binary — there is one install path, the non-isolated one.)
  ensure_cli "Claude Code" claude \
    "$HOME/.local/bin/claude" \
    "https://claude.ai/install.sh"

  ensure_dir "$CLAUDE_DIR"

  # No custom header to inject: the local daemon authenticates with the SAME
  # `sk-llm` key Claude Code carries (`ANTHROPIC_API_KEY`), and the gateway
  # detects a live daemon from that key's server-side activity — so it 307s
  # subscription hops (claude_code) to THIS machine's daemon with no client
  # header. See `docs/proposals/daemon-control-via-neon-longpoll.md`.

  # Write a fresh settings.json containing ONLY our managed keys. Used solely
  # when no settings.json exists yet — NEVER to replace a populated file (that
  # would wipe the user's hooks / permissions / statusLine / …).
  write_settings() {
    cat > "$SETTINGS_FILE" <<JSONEOF
{
  "model": "ultra[1m]",
  "env": {
    "ANTHROPIC_BASE_URL": "${OPENLLM_CLOUD_ORIGIN}",
    "ANTHROPIC_API_KEY": "${API_KEY}",
    "ANTHROPIC_DEFAULT_OPUS_MODEL": "ultra",
    "ANTHROPIC_DEFAULT_SONNET_MODEL": "plus",
    "ANTHROPIC_DEFAULT_HAIKU_MODEL": "lite"
  }
}
JSONEOF
  }

  # Merge our managed keys into an existing settings.json with jq, preserving
  # every other key. Returns non-zero (leaving the file untouched) if jq fails.
  merge_with_jq() {
    local tmp
    tmp=$(mktemp)
    if jq --arg key "$API_KEY" --arg url "${OPENLLM_CLOUD_ORIGIN}" \
       --arg model "ultra[1m]" \
       --arg opus "ultra" --arg sonnet "plus" --arg haiku "lite" '
      .model = $model |
      .env.ANTHROPIC_API_KEY = $key |
      .env.ANTHROPIC_BASE_URL = $url |
      .env.ANTHROPIC_DEFAULT_OPUS_MODEL = $opus |
      .env.ANTHROPIC_DEFAULT_SONNET_MODEL = $sonnet |
      .env.ANTHROPIC_DEFAULT_HAIKU_MODEL = $haiku
    ' "$SETTINGS_FILE" > "$tmp" 2>/dev/null; then
      # Write IN PLACE (not `mv`): under the daemon's OS sandbox settings.json
      # is a FILE-scoped grant — a cross-dir rename into ~/.claude needs
      # create-rights on the (ungranted) parent dir, so `mv` would EACCES, and
      # even a same-dir rename needs the ~/.claude dir granted (it isn't). So we
      # must `cat >` the granted file itself, which truncates BEFORE writing —
      # a mid-write failure (ENOSPC, revoked grant) would otherwise leave
      # settings.json empty. Guard it: back up the current contents first and
      # ROLL BACK on a failed write so the user never loses their config.
      local orig
      orig=$(mktemp)
      cat "$SETTINGS_FILE" > "$orig" 2>/dev/null || true
      if cat "$tmp" > "$SETTINGS_FILE"; then
        rm -f "$tmp" "$orig"
        return 0
      fi
      # Write failed partway — restore the original (best-effort; the file grant
      # covers this in-place write too) so it's left as-found, not truncated.
      cat "$orig" > "$SETTINGS_FILE" 2>/dev/null || true
      rm -f "$tmp" "$orig"
      return 1
    fi
    rm -f "$tmp"
    return 1
  }

  # Merge our env keys into an existing settings.json with python3 (the json
  # stdlib), preserving every other key. Fails closed: if the existing file does
  # NOT parse, it is left exactly as-is and a non-zero status is returned — we
  # never silently overwrite a populated-but-unparseable file.
  merge_with_python() {
    OPENLLM_CLOUD_ORIGIN="$OPENLLM_CLOUD_ORIGIN" API_KEY="$API_KEY" SETTINGS_FILE="$SETTINGS_FILE" \
    python3 - <<'PYEOF'
import json, os, sys

path = os.environ["SETTINGS_FILE"]
try:
    with open(path) as f:
        settings = json.load(f)
except Exception as e:
    print(f"Error: {path} exists but is not valid JSON — refusing to overwrite ({e}).", file=sys.stderr)
    print("  Fix or remove it, then re-run; your file was left untouched.", file=sys.stderr)
    sys.exit(1)

if not isinstance(settings, dict):
    print(f"Error: {path} is not a JSON object — refusing to overwrite.", file=sys.stderr)
    sys.exit(1)

settings["model"] = "ultra[1m]"
env = settings.get("env")
if not isinstance(env, dict):
    env = {}
env["ANTHROPIC_BASE_URL"] = os.environ["OPENLLM_CLOUD_ORIGIN"]
env["ANTHROPIC_API_KEY"] = os.environ["API_KEY"]
env["ANTHROPIC_DEFAULT_OPUS_MODEL"] = "ultra"
env["ANTHROPIC_DEFAULT_SONNET_MODEL"] = "plus"
env["ANTHROPIC_DEFAULT_HAIKU_MODEL"] = "lite"
settings["env"] = env

with open(path, "w") as f:
    json.dump(settings, f, indent=2)
PYEOF
  }

  # Write-once backup of the pre-openllm settings.json (or an .absent marker
  # when it doesn't exist yet) so the user can always recover the original.
  # Guarded (errexit-safe): the helper is wrapper-injected, absent on a raw
  # standalone run. Best-effort — a backup failure never fails the install.
  if type backup_once >/dev/null 2>&1; then backup_once "$SETTINGS_FILE" "setup/claude-code" || true; fi

  if [ ! -f "$SETTINGS_FILE" ]; then
    # No existing config — a fresh write is safe.
    write_settings
  elif has_command jq; then
    if ! merge_with_jq; then
      if has_command python3; then
        # jq couldn't parse/merge — fall back to the python merger (which fails
        # closed on a genuinely unparseable file).
        merge_with_python
      else
        echo "Error: jq failed to update $SETTINGS_FILE — left untouched." >&2
        echo "  Your settings were NOT modified. Fix the file or install python3 and re-run." >&2
        exit 1
      fi
    fi
  elif has_command python3; then
    # merge_with_python exits non-zero (and leaves the file as-is) on a parse
    # error; propagate that under `set -e` so we never claim a false success.
    merge_with_python
  else
    # Neither merger available: do NOT clobber the user's existing settings.
    echo "Error: neither jq nor python3 found — cannot safely update $SETTINGS_FILE." >&2
    echo "  Refusing to overwrite your existing settings. Install jq or python3, then re-run." >&2
    echo "  Or add these keys under .env manually:" >&2
    echo "    ANTHROPIC_BASE_URL=${OPENLLM_CLOUD_ORIGIN}" >&2
    echo "    ANTHROPIC_API_KEY=<your sk-llm key>" >&2
    echo "    ANTHROPIC_DEFAULT_OPUS_MODEL=ultra, ANTHROPIC_DEFAULT_SONNET_MODEL=plus, ANTHROPIC_DEFAULT_HAIKU_MODEL=lite" >&2
    exit 1
  fi

  # If the user previously REJECTED this key in Claude Code's "do you want to
  # use this API key?" prompt, ~/.claude.json remembers it — Claude Code stores
  # the key's LAST 20 chars in `customApiKeyResponses.rejected` and silently
  # skips the prompt forever after. Clear ONLY the rejected entry — never
  # pre-approve — so the next launch re-prompts. Best-effort: a failure here
  # must NOT fail the install (the key is already configured above).
  clear_rejected_key() {
    local claude_json="$HOME/.claude.json"
    [ -f "$claude_json" ] || return 0
    local key_id
    # Claude Code's identifier is `apiKey.slice(-20)` — mirror it exactly.
    key_id=$(printf %s "$API_KEY" | tail -c 20)
    [ -n "$key_id" ] || return 0
    # Cheap pre-check: skip the rewrite entirely when the id isn't in the file.
    grep -qF "$key_id" "$claude_json" 2>/dev/null || return 0
    # About to modify ~/.claude.json — take the write-once original backup.
    if type backup_once >/dev/null 2>&1; then backup_once "$claude_json" "setup/claude-code"; fi
    if has_command jq; then
      local tmp
      tmp=$(mktemp)
      # Type-guard every step (jq `and` short-circuits): a bare `.a.b?` on a
      # non-object `.a` suppresses the error into EMPTY output (not null) while
      # still exiting 0 — which would let the write below truncate the file.
      # The `-s "$tmp"` check is the belt-and-suspenders for the same hazard.
      if jq --arg id "$key_id" '
        if type == "object"
           and ((.customApiKeyResponses | type) == "object")
           and ((.customApiKeyResponses.rejected | type) == "array")
        then .customApiKeyResponses.rejected |= map(select(. != $id))
        else . end
      ' "$claude_json" > "$tmp" 2>/dev/null && [ -s "$tmp" ]; then
        # In-place write, not `mv` — like settings.json above, ~/.claude.json is
        # a FILE-scoped grant under the daemon's OS sandbox, so a rename would
        # EACCES. `cat >` truncates before writing; back up + roll back so a
        # mid-write failure never leaves the file emptied.
        local orig
        orig=$(mktemp)
        cat "$claude_json" > "$orig" 2>/dev/null || true
        if cat "$tmp" > "$claude_json"; then
          rm -f "$tmp" "$orig"
          return 0
        fi
        cat "$orig" > "$claude_json" 2>/dev/null || true
        rm -f "$tmp" "$orig"
        return 0
      fi
      rm -f "$tmp"
      # jq couldn't parse — fall through to python3.
    fi
    if has_command python3; then
      KEY_ID="$key_id" CLAUDE_JSON="$claude_json" python3 - <<'PYEOF' || true
import json, os

path = os.environ["CLAUDE_JSON"]
try:
    with open(path) as f:
        cfg = json.load(f)
except Exception:
    raise SystemExit(0)  # unparseable — leave untouched (best-effort)
if not isinstance(cfg, dict):
    raise SystemExit(0)
resp = cfg.get("customApiKeyResponses")
if not isinstance(resp, dict):
    raise SystemExit(0)
rejected = resp.get("rejected")
key_id = os.environ["KEY_ID"]
if not isinstance(rejected, list) or key_id not in rejected:
    raise SystemExit(0)
resp["rejected"] = [r for r in rejected if r != key_id]
# In-place write (open "w") — never temp+rename; the sandbox grant is
# file-scoped (same constraint as the settings.json merge above).
with open(path, "w") as f:
    json.dump(cfg, f, indent=2)
PYEOF
    fi
    return 0
  }
  clear_rejected_key || true

  echo "Claude Code configured."
  echo "  API base: ${OPENLLM_CLOUD_ORIGIN}"
  echo "  Settings: $SETTINGS_FILE"
  echo "  Daemon:   subscription models (claude_code) run on your local daemon —"
  echo "            start it + connect the provider; the gateway routes to it"
  echo "            automatically via your API key (no extra setup)."
}

do_uninstall() {
  # Best-effort + idempotent: strips ONLY the keys install wrote — the managed
  # `.model` default when it still points at our alias, plus the env keys
  # (`ANTHROPIC_BASE_URL`, `ANTHROPIC_API_KEY`, `ANTHROPIC_DEFAULT_{OPUS,SONNET,
  # HAIKU}_MODEL`) — and leaves the rest of settings.json intact. No-op when the
  # file is absent.
  if [ ! -f "$SETTINGS_FILE" ]; then
    echo "  No settings.json found — nothing to undo."
  else
    if has_command jq; then
      local tmp
      tmp=$(mktemp)
      # Only overwrite + claim success if jq actually succeeded — otherwise clean
      # up the temp file and leave settings.json untouched (no false success).
      if jq '
        (if .model == "ultra[1m]" then del(.model) else . end)
        | if .env then
          .env |= del(
            .ANTHROPIC_BASE_URL,
            .ANTHROPIC_API_KEY,
            .ANTHROPIC_DEFAULT_OPUS_MODEL,
            .ANTHROPIC_DEFAULT_SONNET_MODEL,
            .ANTHROPIC_DEFAULT_HAIKU_MODEL
          )
          | if (.env | length) == 0 then del(.env) else . end
        else . end
      ' "$SETTINGS_FILE" > "$tmp"; then
        # In-place write, not `mv` — settings.json is a FILE-scoped sandbox
        # grant; a cross-dir rename into ~/.claude would EACCES (see install).
        # `cat >` truncates before writing, so back up the original and ROLL
        # BACK on a failed write — otherwise "left untouched" would be a lie
        # (the file was already emptied).
        local orig
        orig=$(mktemp)
        cat "$SETTINGS_FILE" > "$orig" 2>/dev/null || true
        if cat "$tmp" > "$SETTINGS_FILE"; then
          rm -f "$tmp" "$orig"
          echo "  Removed OpenLLM keys from $SETTINGS_FILE"
        else
          cat "$orig" > "$SETTINGS_FILE" 2>/dev/null || true
          rm -f "$tmp" "$orig"
          echo "  Warning: could not write $SETTINGS_FILE — left untouched." >&2
        fi
      else
        rm -f "$tmp"
        echo "  Warning: jq failed — leaving settings.json untouched." >&2
      fi
    else
      echo "  Warning: jq not found — leaving settings.json untouched." >&2
      echo "  Manually remove the ANTHROPIC_* keys under .env from $SETTINGS_FILE" >&2
    fi
  fi

  echo "Claude Code OpenLLM configuration removed."
}

# Print one JSON line describing install state. Installed ⇔ our managed
# ANTHROPIC_BASE_URL env key is present in settings.json (the durable signal
# install writes). Exit 0 always; the JSON IS the payload. No key, no network.
# (The `diverged` flag is NOT computed here — the gateway's state wrapper
# injects it by comparing the install-time version stamp against the current
# bundle version.)
do_state() {
  local installed="false"
  if [ -f "$SETTINGS_FILE" ] && grep -q "ANTHROPIC_BASE_URL" "$SETTINGS_FILE" 2>/dev/null; then
    installed="true"
  fi
  version="null"
  iv="$(read_install_version)"
  [ -n "$iv" ] && version="\"$iv\""
  printf '{"installed":%s,"version":%s,"installed_sha256":"%s","installed_commit":"%s"}\n' "$installed" "$version" "$(read_install_stamp)" "$(read_install_commit)"
}

MODE="install"
while [ $# -gt 0 ]; do
  case "$1" in
    -u) MODE="uninstall"; shift ;;
    -s) MODE="state"; shift ;;
    *) echo "usage: install.sh [-u|-s]" >&2; exit 2 ;;
  esac
done

case "$MODE" in
  install)   do_install; record_install_stamp ;;
  uninstall) do_uninstall; clear_install_stamp ;;
  state)     do_state ;;
esac
}
_openllm_main "$@"
